class Solution:
    def countBits(self, n: int) -> list[int]:
        def popcount(x):
            count = 0
            while x:
                x &= x - 1
                count += 1
            return count
        return [popcount(i) for i in range(n + 1)]

class Solution:
    def countBits(self, n: int) -> list[int]:
        ans = [0] * (n + 1)
        for i in range(1, n + 1):
            ans[i] = ans[i >> 1] + (i & 1)
        return ans

class Solution:
    def countBits(self, n: int) -> list[int]:
        ans = [0] * (n + 1)
        for i in range(1, n + 1):
            ans[i] = ans[i & (i - 1)] + 1
        return ans

class Solution:
    def reverseBits(self, n: int) -> int:
        result = 0
        for i in range(32):
            result = (result << 1) | (n & 1)  # shift result left, add last bit of n
            n >>= 1                            # shift n right
        return result

class Solution:
    def missingNumber(self, nums: list[int]) -> int:
        n = len(nums)
        expected = n * (n + 1) // 2
        return expected - sum(nums)

class Solution:
    def missingNumber(self, nums: list[int]) -> int:
        result = len(nums)  # start with n (the missing candidate)
        for i, num in enumerate(nums):
            result ^= i ^ num
        return result

class Solution:
    def missingNumber(self, nums: list[int]) -> int:
        nums.sort()
        for i in range(len(nums)):
            if nums[i] != i:
                return i
        return len(nums)  # missing number is n

class Solution:
    def getSum(self, a: int, b: int) -> int:
        mask = 0xFFFFFFFF  # 32-bit mask
        while b != 0:
            carry = (a & b) << 1
            a = (a ^ b) & mask  # sum without carry, masked to 32 bits
            b = carry & mask    # carry, masked to 32 bits
        # if a is negative in 32-bit (highest bit set), convert to Python negative
        return a if a < 0x80000000 else ~(a ^ mask)

class Solution:
    def getSum(self, a: int, b: int) -> int:
        mask = 0xFFFFFFFF
        # base case: no carry
        if b == 0:
            # handle sign for Python's unbounded integers
            return a if a < 0x80000000 else ~(a ^ mask)
        # recursive case: sum without carry, and the carry shifted left
        return self.getSum((a ^ b) & mask, ((a & b) << 1) & mask)
